import { Tooltip, TooltipTrigger, TooltipContent, TooltipProvider } from '@radix-ui/react-tooltip';
import { InfoCircledIcon } from '@radix-ui/react-icons'; // Assuming an icon library

function IconTooltip() {
  return (
    <TooltipProvider>
      <Tooltip>
        <TooltipTrigger asChild>
          <button aria-label="More info">
            <InfoCircledIcon />
          </button>
        </TooltipTrigger>
        <TooltipContent>
          <p>Additional information about this section.</p>
        </TooltipContent>
      </Tooltip>
    </TooltipProvider>
  );
}

export default IconTooltip;

import { Tooltip, TooltipTrigger, TooltipContent, TooltipProvider } from '@radix-ui/react-tooltip';

function TruncatedTextTooltip() {
  const longText = "This is a very long piece of text that needs to be truncated to fit into a small space. The tooltip will reveal the full content.";
  return (
    <TooltipProvider>
      <Tooltip>
        <TooltipTrigger asChild>
          <p style={{ maxWidth: '100px', whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>
            {longText}
          </p>
        </TooltipTrigger>
        <TooltipContent>
          <p>{longText}</p>
        </TooltipContent>
      </Tooltip>
    </TooltipProvider>
  );
}

export default TruncatedTextTooltip;

import { Tooltip, TooltipTrigger, TooltipContent, TooltipProvider } from '@radix-ui/react-tooltip';

function LinkTooltip() {
  return (
    <TooltipProvider>
      <Tooltip>
        <TooltipTrigger asChild>
          <span>Learn more <a href="#" style={{ textDecoration: 'underline' }}>here</a></span>
